// 生成邮件列表HTML
function generateEmailHTML(data) {
    const total = data.length;

    if (total === 0) {
        return `
                    <div class="email-container">
                        <div class="email-header">
                            <span class="email-title">我的邮件</span>
                        </div>
                        <div class="email-empty">
                            <div class="email-empty-icon">📧</div>
                            <p class="email-empty-text">暂无未读邮件</p>
                        </div>
                    </div>
                `;
    }

    let html = `
                <div class="email-container">
                    <div class="email-header">
                        <span class="email-title">我的邮件</span>
                    </div>
                    <div class="email-list">
            `;

    data.forEach(item => {
        const timeStr = formatTimeDisplay(item.time);

        html += `
                    <div class="email-item" docid="${item.id}">
                        <div class="email-indicator" ${!item.unread ? 'style="background-color: #9ca3af;"' : ''}></div>
                        <div class="email-content">
                            <div class="email-subject">${item.subject}</div>
                            <div class="email-info">
                                <span class="email-sender">${item.sender}</span>
                                <span class="email-time">${timeStr}</span>
                            </div>
                        </div>
                    </div>
                `;
    });

    html += `
                    </div>
                </div>
            `;

    return html;
}

// 格式化时间显示
function formatTimeDisplay(timeStr) {
    const now = new Date();
    const itemTime = new Date(timeStr);

    if (isNaN(itemTime.getTime())) {
        return "时间未知";
    }

    const diffMs = now - itemTime;
    const diffHours = diffMs / (1000 * 60 * 60);

    if (diffHours < 1) {
        const diffMins = Math.floor(diffMs / (1000 * 60));
        return diffMins < 1 ? '刚刚' : `${diffMins}分钟前`;
    } else if (diffHours < 24) {
        return `${Math.floor(diffHours)}小时前`;
    } else if (diffHours < 48) {
        return '昨天';
    } else {
        const month = itemTime.getMonth() + 1;
        const day = itemTime.getDate();
        return `${month}月${day}日`;
    }
}


