// 格式化金额
function formatCurrency(amount) {
    return amount.toLocaleString('zh-CN', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
    });
}

// 生成工资条HTML
function generateSalaryHTML(data) {
    // 计算应发总额
    const totalEarnings = data.earnings.reduce((sum, item) => sum + item.amount, 0);

    // 计算扣款总额
    const totalDeductions = data.deductions.reduce((sum, item) => sum + item.amount, 0);

    // 计算实发工资
    const netPay = totalEarnings - totalDeductions;

    let html = `
                <div class="salary-payslip">
                    <!-- 头部 -->
                    <div class="salary-header">
                        <div class="salary-title">工资条</div>
                        <div class="salary-subtitle">${data.period}</div>
                    </div>

                    <!-- 员工信息 -->
                    <div class="salary-info-grid">
                        <div class="salary-info-item">
                            <span class="salary-label">姓名</span>
                            <span class="salary-value">${data.name}</span>
                        </div>
                        <div class="salary-info-item">
                            <span class="salary-label">工号</span>
                            <span class="salary-value">${data.employeeId}</span>
                        </div>
                        <div class="salary-info-item">
                            <span class="salary-label">部门</span>
                            <span class="salary-value">${data.department}</span>
                        </div>
                        <div class="salary-info-item">
                            <span class="salary-label">发放日期</span>
                            <span class="salary-value">${data.payDate}</span>
                        </div>
                    </div>

                    <!-- 金额明细 -->
                    <div class="salary-details">
                        <!-- 应发项目 -->
                        <div class="salary-section">
                            <h3 class="salary-section-title">应发项目 (合计: ¥${formatCurrency(totalEarnings)})</h3>
            `;

    // 添加应发项目
    data.earnings.forEach(item => {
        html += `
                    <div class="salary-item-row">
                        <span class="salary-item-name">${item.name}</span>
                        <span class="salary-item-amount salary-positive">${formatCurrency(item.amount)}</span>
                    </div>
                `;
    });

    html += `
                        </div>

                        <!-- 扣款项目 -->
                        <div class="salary-section">
                            <h3 class="salary-section-title">扣款项目 (合计: ¥${formatCurrency(totalDeductions)})</h3>
            `;

    // 添加扣款项目
    data.deductions.forEach(item => {
        html += `
                    <div class="salary-item-row">
                        <span class="salary-item-name">${item.name}</span>
                        <span class="salary-item-amount salary-negative">-${formatCurrency(item.amount)}</span>
                    </div>
                `;
    });

    html += `
                        </div>
                    </div>

                    <!-- 总计 -->
                    <div class="salary-total">
                        <span class="salary-total-label">实发工资</span>
                        <span class="salary-total-amount">¥${formatCurrency(netPay)}</span>
                    </div>

                    <!-- 底部 -->
                    <div class="salary-footer">
                        ${data.footerNote}
                    </div>
                </div>
            `;

    return html;
}



