extra.script:
if (data.length == 0) {
    new Element("div", { "text": "暂无日程安排" }).inject(node);
    return;
}

const scheduleData = data;

// 星期映射
const weekDays = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];

// 格式化日期函数
function formatDate(dateStr) {
    const date = new Date(dateStr);
    const year = date.getFullYear();
    const month = date.getMonth() + 1;
    const day = date.getDate();
    const weekDay = weekDays[date.getDay()];

    return {
        dateText: `${year}年${month}月${day}日`,
        weekDay: weekDay,
        dateObj: date
    };
}

// 格式化时间函数
function formatTime(dateStr) {
    const date = new Date(dateStr);
    const hours = date.getHours().toString().padStart(2, '0');
    const minutes = date.getMinutes().toString().padStart(2, '0');

    return `${hours}:${minutes}`;
}

// 获取事件类别
function getEventCategory(event) {
    if (event.isAllDayEvent) {
        return "all-day-badge";
    } else if (event.source === "PERSONAL") {
        return "personal-event-badge";
    } else {
        return "normal-event-badge";
    }
}

// 获取事件类别文本
function getEventCategoryText(event) {
    if (event.isAllDayEvent) {
        return "全天";
    } else if (event.source === "PERSONAL") {
        return "个人";
    } else {
        return "日程";
    }
}

// 获取时间显示文本
function getTimeDisplay(event) {
    if (event.isAllDayEvent) {
        return "全天";
    } else {
        const startTime = formatTime(event.startTimeStr);
        const endTime = formatTime(event.endTimeStr);
        return `${startTime} - ${endTime}`;
    }
}

// 按日期分组事件
function groupEventsByDate(events) {
    const grouped = {};

    events.forEach(event => {
        // 使用startTime作为日期键
        const dateKey = event.startTime.split(' ')[0]; // 只取日期部分

        if (!grouped[dateKey]) {
            grouped[dateKey] = [];
        }

        grouped[dateKey].push(event);
    });

    return grouped;
}

// 对同一天的事件进行排序（全天事件在前，然后按开始时间排序）
function sortEvents(events) {
    return events.sort((a, b) => {
        // 全天事件排在最前
        if (a.isAllDayEvent && !b.isAllDayEvent) return -1;
        if (!a.isAllDayEvent && b.isAllDayEvent) return 1;

        // 非全天事件按开始时间排序
        if (!a.isAllDayEvent && !b.isAllDayEvent) {
            return new Date(a.startTimeStr) - new Date(b.startTimeStr);
        }

        return 0;
    });
}

// 生成HTML
function generateScheduleHTML(events) {
    // 按日期分组
    const groupedEvents = groupEventsByDate(events);

    // 获取所有日期并排序
    const dates = Object.keys(groupedEvents).sort();

    let html = '<div class="schedule-compact">';

    dates.forEach(dateKey => {
        const dateInfo = formatDate(dateKey);
        const dayEvents = groupedEvents[dateKey];

        // 对当天事件进行排序
        const sortedEvents = sortEvents(dayEvents);

        html += `
                <div class="date-section">
                    <div class="date-header">
                        <span class="date-day">${dateInfo.weekDay}</span>
                        <span class="date-text">${dateInfo.dateText}</span>
                    </div>`;

        sortedEvents.forEach(event => {
            const timeDisplay = getTimeDisplay(event);
            const eventCategory = getEventCategory(event);
            const categoryText = getEventCategoryText(event);

            html += `
                    <div class="schedule-item">
                        <div class="time-column">
                            <span class="time-icon">${event.isAllDayEvent ? '📅' : '⏰'}</span>
                            ${timeDisplay}
                        </div>
                        <div class="details-column">
                            <div class="event-title">
                                ${event.title}
                                <span class="event-color-indicator" style="background-color: ${event.color};"></span>
                            </div>
                            <div class="event-category ${eventCategory}">${categoryText}</div>
                        </div>
                    </div>`;
        });

        html += `</div>`;
    });

    html += '</div>';

    return html;
}

const scheduleHTML = generateScheduleHTML(scheduleData);
