const todoData = data.dataList;
const total = data.total;

// 生成待办列表HTML
function generateTodoHTML(data) {


    // 如果没有待办事项
    if (total === 0) {
        return `
                    <div class="todo-container">
                        <div class="todo-header">
                            <span class="todo-header-title">待处理事项</span>
                            <span class="todo-header-count">0项</span>
                        </div>
                        <div class="todo-empty">
                            <div class="todo-empty-icon">📋</div>
                            <p class="todo-empty-text">暂无待处理事项</p>
                        </div>
                    </div>
                `;
    }

    let html = `
                <div class="todo-container">
                    <div class="todo-header">
                        <span class="todo-header-title">待处理事项</span>
                        <span class="todo-header-count">${total}项</span>
                    </div>
                    <div class="todo-list">
            `;

    // 添加待办事项
    data.forEach(item => {
        // 格式化时间显示
        const timeStr = formatTimeDisplay(item.time);
        const indicatorClass = item.urgent ? 'todo-indicator todo-indicator-urgent' : 'todo-indicator';

        html += `
                    <div class="todo-item" work="${item.work}">
                        <div class="${indicatorClass}"></div>
                        <div class="todo-content">
                            <div class="todo-title">${item.title}</div>
                            <div class="todo-meta">
                                <span class="todo-process">${item.process}</span>
                                <span class="todo-time">
                                    <span>🕒</span>
                                    ${timeStr}
                                </span>
                            </div>
                        </div>
                    </div>
                `;
    });

    html += `
                    </div>
                </div>
            `;

    return html;
}

// 格式化时间显示
function formatTimeDisplay(timeStr) {
    return timeStr;
    const now = new Date();
    const itemTime = new Date(timeStr);

    // 处理无效日期
    if (isNaN(itemTime.getTime())) {
        return "时间未知";
    }

    const diffMs = now - itemTime;
    const diffHours = diffMs / (1000 * 60 * 60);

    if (diffHours < 1) {
        const diffMins = Math.floor(diffMs / (1000 * 60));
        return diffMins < 1 ? '刚刚' : `${diffMins}分钟前`;
    } else if (diffHours < 24) {
        return `${Math.floor(diffHours)}小时前`;
    } else if (diffHours < 48) {
        return '昨天';
    } else {
        // 显示具体日期
        const month = itemTime.getMonth() + 1;
        const day = itemTime.getDate();
        const hours = itemTime.getHours().toString().padStart(2, '0');
        const minutes = itemTime.getMinutes().toString().padStart(2, '0');
        return `${month}月${day}日 ${hours}:${minutes}`;
    }
}

